/**
 * Quick test: create folders + upload a tiny JPEG under the PoW root.
 * Usage: node scripts/probe-drive-upload.mjs
 */
import { readFileSync, existsSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.join(path.dirname(fileURLToPath(import.meta.url)), "..");
const envPath = path.join(root, ".env");
if (existsSync(envPath)) {
  for (const raw of readFileSync(envPath, "utf8").split(/\r?\n/)) {
    const line = raw.trim();
    if (!line || line.startsWith("#")) continue;
    const eq = line.indexOf("=");
    if (eq <= 0) continue;
    const k = line.slice(0, eq).trim();
    let v = line.slice(eq + 1).trim();
    if (
      (v.startsWith('"') && v.endsWith('"')) ||
      (v.startsWith("'") && v.endsWith("'"))
    ) {
      v = v.slice(1, -1);
    }
    if (process.env[k] === undefined) process.env[k] = v;
  }
}

const { uploadPowImage, driveAuthMode } = await import("../src/lib/drive.js");

// Minimal valid JPEG
const jpeg = Buffer.from(
  "",
  "base64"
);

const today = new Date().toLocaleDateString("en-CA", {
  timeZone: "Asia/Bangkok",
});

const result = await uploadPowImage({
  buffer: jpeg,
  filename: `_probe_${Date.now()}.jpg`,
  mimeType: "image/jpeg",
  date: today,
  staffName: "ทดสอบพนักงาน",
  customerName: "ทดสอบลูกค้า",
});

console.log("authMode:", result.authMode || driveAuthMode());
console.log("path:", result.pathHint);
console.log("folderId:", result.folderId);
console.log("openUrl:", result.openUrl);
